-- ── Contract: wm_operations.order_journey_events v0.1.0 ──
COMMENT ON VIEW connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_order_journey_events IS
  'Order/Batch Journey Timeline events -- long-format per-order event feed. One row per plant_id x order_id x event_seq. Event types: ORDER_CREATED, RELEASED, TR_CREATED, STAGING_CONFIRMED, PI_START, OPERATION_CONFIRMED, PI_END, GR_POSTED, COMPONENT_ISSUED, QM_LOT_CREATED, QM_UD_TAKEN. PI and QM events absent at plants without those silver tables. event_seq is row_number ordered by event_ts NULLS LAST within the order. No date-relative columns -- no _live wrapper; reads _secured directly. Grain: one row per plant_id, order_id, and event_seq. Contract: wm_operations.order_journey_events v0.1.0. Freshness SLA: expected 60 min, warning 120 min, critical 240 min. Row-level access key: plant_id.';
ALTER VIEW connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_order_journey_events SET TAGS (
  'contract_id' = 'wm_operations.order_journey_events',
  'contract_version' = '0.1.0',
  'contract_grain' = 'one row per plant_id, order_id, and event_seq',
  'freshness_expected_minutes' = '60'
);
-- (no column descriptions in manifest for vw_consumption_wm_operations_order_journey_events)

