COMMENT ON VIEW connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_wip_stages IS
  'Active process order WIP funnel — one row per plant_id x order_id for released, not-finished orders. stage values: RELEASED / STAGING / STAGED / IN_PRODUCTION / GR_PARTIAL / GR_COMPLETE, derived deterministically from journey milestones. Includes order qty, material, scheduled dates. No current_date/current_timestamp. Grain: one row per plant_id and order_id (active orders only). Contract: wm_operations.wip_stages v0.1.0. Freshness SLA: expected 60 min, warning 120 min, critical 240 min. Row-level access key: plant_id.';
ALTER VIEW connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_wip_stages SET TAGS (
  'contract_id' = 'wm_operations.wip_stages',
  'contract_version' = '0.1.0',
  'contract_grain' = 'one row per plant_id and order_id (active orders only)',
  'freshness_expected_minutes' = '60'
);
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_wip_stages.stage IS
  'RELEASED | STAGING | STAGED | IN_PRODUCTION | GR_PARTIAL | GR_COMPLETE';

