-- ── Contract: wm_operations.component_variance v0.2.0 ──
COMMENT ON VIEW connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance IS
  'Order + material grain material variance for the Yield & Loss waterfall. One row per plant_id, order_id, material_id (aggregated from reservation_requirement). Silver goods_movement carries no reservation references (MSEG has no RSNUM/RSPOS in the replication schema), so reservation grain would double-count issued_qty for orders with multiple RESB rows for the same material. Grain changed from reservation-item to order+material in v0.2.0. variance_qty = issued_qty - required_qty (positive = over-issue / loss; negative = under-issue). est_loss_value = over-issued qty × standard_price / price_unit (null when no price data). Quantities stay in each row''s own base_uom — no cross-material aggregation in gold. Source: gold_wm_order_component_variance (reservation_requirement + goods_movement + material_valuation). Grain: one row per plant_id, order_id, and material_id. Contract: wm_operations.component_variance v0.2.0. Freshness SLA: expected 60 min, warning 120 min, critical 240 min. Row-level access key: plant_id.';
ALTER VIEW connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance SET TAGS (
  'contract_id' = 'wm_operations.component_variance',
  'contract_version' = '0.2.0',
  'contract_grain' = 'one row per plant_id, order_id, and material_id',
  'freshness_expected_minutes' = '60'
);
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.plant_id IS
  'SAP plant ID';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.order_id IS
  'Process order number (AUFNR)';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.material_id IS
  'Component material code';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.material_name IS
  'Component material description';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.uom IS
  'Base unit of measure for quantities in this row';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.movement_type_code IS
  'SAP movement type code (261 = goods issue for production; 261X = batch-where variant)';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.required_qty IS
  'Required component quantity aggregated from reservation_requirement (RESB) at order+material grain';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.withdrawn_qty IS
  'Withdrawn quantity from reservations (RESB ENMNG — already-issued signal from planning)';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.issued_qty IS
  'Net issued quantity from goods movements (261 minus 262 reversals) against this order+material';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.variance_qty IS
  'issued_qty minus required_qty (positive = over-issue / loss; negative = under-issue)';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.variance_pct IS
  'variance_qty / required_qty (null when required_qty is zero; positive = over-issued fraction)';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.est_loss_value IS
  'Estimated over-issue value = MAX(variance_qty, 0) × standard_price / price_unit (null when no standard_price available from material_valuation)';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.standard_price IS
  'Standard price per price_unit from material_valuation (MBEW STPRS)';
COMMENT ON COLUMN connected_plant_prod.gold_io_reporting.vw_consumption_wm_operations_component_variance.is_final_issue IS
  'True when the reservation carries the final-issue flag (RESB KZEAR)';
